import { Injectable } from '@angular/core';
import { CanActivate, Router, ActivatedRouteSnapshot } from '@angular/router';
import { FeatureFlagsService } from 'libs/feature-flags';
import { AccessDecisionService } from 'libs/access-decision';

@Injectable({ providedIn: 'root' })
export class RouteGateGuard implements CanActivate {
  constructor(
    private flags: FeatureFlagsService,
    private access: AccessDecisionService,
    private router: Router
  ) {}

  async canActivate(route: ActivatedRouteSnapshot) {
    const featureKey = route.data?.feature as string | undefined;
    if (featureKey && !this.flags.isEnabled(featureKey)) {
      return false; // feature disabled
    }
    const resource = route.data?.resource || route.url.join('/');
    const decision = await this.access.decide({ action: 'view', resource });
    if (decision.allow) return true;
    this.router.navigate(['/no-access']);
    return false;
  }
}
